import { useEffect, useRef, useState, useCallback } from 'react';
import { cn } from '@/lib/utils';

interface ViewportState {
  zoom: number;
  pan: { x: number; y: number };
  rotation: number;
  flipH: boolean;
  flipV: boolean;
  windowWidth: number;
  windowLevel: number;
  invert: boolean;
}

interface SideBySideModeProps {
  imageIdA: string;
  imageIdB: string;
  orientation?: 'horizontal' | 'vertical';
  syncScroll?: boolean;
  syncZoom?: boolean;
  className?: string;
}

const defaultViewport: ViewportState = {
  zoom: 1,
  pan: { x: 0, y: 0 },
  rotation: 0,
  flipH: false,
  flipV: false,
  windowWidth: 400,
  windowLevel: 40,
  invert: false,
};

function renderImageToCanvas(
  canvas: HTMLCanvasElement,
  img: HTMLImageElement,
  viewport: ViewportState
) {
  const ctx = canvas.getContext('2d');
  if (!ctx) return;

  canvas.width = canvas.parentElement?.clientWidth || canvas.width;
  canvas.height = canvas.parentElement?.clientHeight || canvas.height;

  ctx.clearRect(0, 0, canvas.width, canvas.height);
  ctx.save();

  ctx.translate(canvas.width / 2, canvas.height / 2);
  ctx.scale(viewport.zoom, viewport.zoom);
  ctx.rotate((viewport.rotation * Math.PI) / 180);
  if (viewport.flipH) ctx.scale(-1, 1);
  if (viewport.flipV) ctx.scale(1, -1);
  ctx.translate(viewport.pan.x, viewport.pan.y);

  const scale = Math.min(canvas.width / img.width, canvas.height / img.height) * 0.9;
  const x = (-img.width * scale) / 2;
  const y = (-img.height * scale) / 2;

  ctx.drawImage(img, x, y, img.width * scale, img.height * scale);

  if (viewport.windowWidth !== 400 || viewport.windowLevel !== 40) {
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imageData.data;
    const min = viewport.windowLevel - viewport.windowWidth / 2;
    const max = viewport.windowLevel + viewport.windowWidth / 2;

    for (let i = 0; i < data.length; i += 4) {
      const gray = (data[i] + data[i + 1] + data[i + 2]) / 3;
      const normalized = ((gray - min) / (max - min)) * 255;
      const clamped = Math.max(0, Math.min(255, normalized));
      data[i] = clamped;
      data[i + 1] = clamped;
      data[i + 2] = clamped;
    }
    ctx.putImageData(imageData, 0, 0);
  }

  if (viewport.invert) {
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imageData.data;
    for (let i = 0; i < data.length; i += 4) {
      data[i] = 255 - data[i];
      data[i + 1] = 255 - data[i + 1];
      data[i + 2] = 255 - data[i + 2];
    }
    ctx.putImageData(imageData, 0, 0);
  }

  ctx.restore();
}

export function SideBySideMode({
  imageIdA,
  imageIdB,
  orientation = 'horizontal',
  syncScroll = true,
  syncZoom = true,
  className,
}: SideBySideModeProps) {
  const canvasARef = useRef<HTMLCanvasElement>(null);
  const canvasBRef = useRef<HTMLCanvasElement>(null);
  const containerARef = useRef<HTMLDivElement>(null);
  const containerBRef = useRef<HTMLDivElement>(null);
  const imgARef = useRef<HTMLImageElement | null>(null);
  const imgBRef = useRef<HTMLImageElement | null>(null);

  const [viewportA, setViewportA] = useState<ViewportState>({ ...defaultViewport });
  const [viewportB, setViewportB] = useState<ViewportState>({ ...defaultViewport });
  const [isLoadingA, setIsLoadingA] = useState(true);
  const [isLoadingB, setIsLoadingB] = useState(true);

  const isSyncingRef = useRef(false);

  const loadImage = useCallback(
    (imageId: string, imgRef: React.MutableRefObject<HTMLImageElement | null>, setLoaded: (v: boolean) => void) => {
      if (!imageId) return;
      setLoaded(false);
      const img = new Image();
      img.crossOrigin = 'anonymous';
      img.onload = () => {
        imgRef.current = img;
        setLoaded(true);
      };
      img.onerror = () => {
        imgRef.current = null;
        setLoaded(false);
      };
      img.src = `/api/images/${imageId}/file`;
    },
    []
  );

  useEffect(() => {
    loadImage(imageIdA, imgARef, setIsLoadingA);
  }, [imageIdA, loadImage]);

  useEffect(() => {
    loadImage(imageIdB, imgBRef, setIsLoadingB);
  }, [imageIdB, loadImage]);

  useEffect(() => {
    if (canvasARef.current && imgARef.current) {
      renderImageToCanvas(canvasARef.current, imgARef.current, viewportA);
    }
  }, [viewportA, isLoadingA]);

  useEffect(() => {
    if (canvasBRef.current && imgBRef.current) {
      renderImageToCanvas(canvasBRef.current, imgBRef.current, viewportB);
    }
  }, [viewportB, isLoadingB]);

  const handleMouseDown = useCallback(
    (side: 'A' | 'B') => (e: React.MouseEvent<HTMLCanvasElement>) => {
      const startX = e.clientX;
      const startY = e.clientY;
      const currentViewport = side === 'A' ? viewportA : viewportB;
      const setViewport = side === 'A' ? setViewportA : setViewportB;
      const startPan = { ...currentViewport.pan };
      const startZoom = currentViewport.zoom;

      const handleMouseMove = (moveEvent: MouseEvent) => {
        const deltaX = moveEvent.clientX - startX;
        const deltaY = moveEvent.clientY - startY;

        const newPan = {
          x: startPan.x + deltaX / currentViewport.zoom,
          y: startPan.y + deltaY / currentViewport.zoom,
        };

        setViewport((prev) => ({ ...prev, pan: newPan }));

        if (syncScroll && !isSyncingRef.current) {
          isSyncingRef.current = true;
          const otherSet = side === 'A' ? setViewportB : setViewportA;
          otherSet((prev) => ({ ...prev, pan: newPan }));
          isSyncingRef.current = false;
        }
      };

      const handleMouseUp = () => {
        window.removeEventListener('mousemove', handleMouseMove);
        window.removeEventListener('mouseup', handleMouseUp);
      };

      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    },
    [viewportA, viewportB, syncScroll]
  );

  const handleWheel = useCallback(
    (side: 'A' | 'B') => (e: React.WheelEvent<HTMLCanvasElement>) => {
      e.preventDefault();
      const zoomFactor = e.deltaY > 0 ? 0.9 : 1.1;
      const currentViewport = side === 'A' ? viewportA : viewportB;
      const setViewport = side === 'A' ? setViewportA : setViewportB;
      const newZoom = Math.max(0.1, Math.min(10, currentViewport.zoom * zoomFactor));

      setViewport((prev) => ({ ...prev, zoom: newZoom }));

      if (syncZoom && !isSyncingRef.current) {
        isSyncingRef.current = true;
        const otherSet = side === 'A' ? setViewportB : setViewportA;
        otherSet((prev) => ({ ...prev, zoom: newZoom }));
        isSyncingRef.current = false;
      }
    },
    [viewportA, viewportB, syncZoom]
  );

  const isHorizontal = orientation === 'horizontal';

  return (
    <div
      className={cn(
        'flex w-full h-full',
        isHorizontal ? 'flex-row' : 'flex-col',
        className
      )}
    >
      <div ref={containerARef} className="relative flex-1 bg-black overflow-hidden">
        {isLoadingA && (
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="text-white text-sm">加载中...</div>
          </div>
        )}
        <canvas
          ref={canvasARef}
          className="w-full h-full cursor-crosshair"
          onMouseDown={handleMouseDown('A')}
          onWheel={handleWheel('A')}
        />
        <div className="absolute top-2 left-2 text-xs text-white/70 bg-black/50 px-2 py-1 rounded">
          A
        </div>
        <div className="absolute bottom-2 left-2 text-xs text-white/70">
          <div>缩放: {(viewportA.zoom * 100).toFixed(0)}%</div>
          <div>窗宽/窗位: {viewportA.windowWidth}/{viewportA.windowLevel}</div>
        </div>
      </div>

      <div className={cn('bg-border', isHorizontal ? 'w-1' : 'h-1')} />

      <div ref={containerBRef} className="relative flex-1 bg-black overflow-hidden">
        {isLoadingB && (
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="text-white text-sm">加载中...</div>
          </div>
        )}
        <canvas
          ref={canvasBRef}
          className="w-full h-full cursor-crosshair"
          onMouseDown={handleMouseDown('B')}
          onWheel={handleWheel('B')}
        />
        <div className="absolute top-2 left-2 text-xs text-white/70 bg-black/50 px-2 py-1 rounded">
          B
        </div>
        <div className="absolute bottom-2 left-2 text-xs text-white/70">
          <div>缩放: {(viewportB.zoom * 100).toFixed(0)}%</div>
          <div>窗宽/窗位: {viewportB.windowWidth}/{viewportB.windowLevel}</div>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useRef, useState, useCallback } from 'react';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';

interface ViewportState {
  zoom: number;
  pan: { x: number; y: number };
  rotation: number;
  flipH: boolean;
  flipV: boolean;
  windowWidth: number;
  windowLevel: number;
  invert: boolean;
}

type BlendMode = 'normal' | 'difference' | 'lighten' | 'darken';

interface OverlayModeProps {
  imageIdA: string;
  imageIdB: string;
  className?: string;
}

const defaultViewport: ViewportState = {
  zoom: 1,
  pan: { x: 0, y: 0 },
  rotation: 0,
  flipH: false,
  flipV: false,
  windowWidth: 400,
  windowLevel: 40,
  invert: false,
};

const BLEND_MODES: { value: BlendMode; label: string }[] = [
  { value: 'normal', label: '正常' },
  { value: 'difference', label: '差异' },
  { value: 'lighten', label: '变亮' },
  { value: 'darken', label: '变暗' },
];

function renderOverlayToCanvas(
  canvas: HTMLCanvasElement,
  imgA: HTMLImageElement,
  imgB: HTMLImageElement,
  viewport: ViewportState,
  opacity: number,
  blendMode: BlendMode
) {
  const ctx = canvas.getContext('2d');
  if (!ctx) return;

  canvas.width = canvas.parentElement?.clientWidth || canvas.width;
  canvas.height = canvas.parentElement?.clientHeight || canvas.height;

  ctx.clearRect(0, 0, canvas.width, canvas.height);

  const renderSingleImage = (img: HTMLImageElement, globalAlpha: number) => {
    ctx.save();
    ctx.globalAlpha = globalAlpha;

    ctx.translate(canvas.width / 2, canvas.height / 2);
    ctx.scale(viewport.zoom, viewport.zoom);
    ctx.rotate((viewport.rotation * Math.PI) / 180);
    if (viewport.flipH) ctx.scale(-1, 1);
    if (viewport.flipV) ctx.scale(1, -1);
    ctx.translate(viewport.pan.x, viewport.pan.y);

    const scale = Math.min(canvas.width / img.width, canvas.height / img.height) * 0.9;
    const x = (-img.width * scale) / 2;
    const y = (-img.height * scale) / 2;

    ctx.drawImage(img, x, y, img.width * scale, img.height * scale);
    ctx.restore();
  };

  // Canvas blend mode mapping
  const canvasBlendMode: GlobalCompositeOperation =
    blendMode === 'normal' ? 'source-over' :
    blendMode === 'difference' ? 'difference' :
    blendMode === 'lighten' ? 'lighten' :
    'darken';

  ctx.save();
  ctx.globalCompositeOperation = 'source-over';
  renderSingleImage(imgA, 1);

  ctx.globalCompositeOperation = canvasBlendMode;
  renderSingleImage(imgB, opacity);

  ctx.globalCompositeOperation = 'source-over';
  ctx.restore();

  // Apply window/level
  if (viewport.windowWidth !== 400 || viewport.windowLevel !== 40) {
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imageData.data;
    const min = viewport.windowLevel - viewport.windowWidth / 2;
    const max = viewport.windowLevel + viewport.windowWidth / 2;

    for (let i = 0; i < data.length; i += 4) {
      const gray = (data[i] + data[i + 1] + data[i + 2]) / 3;
      const normalized = ((gray - min) / (max - min)) * 255;
      const clamped = Math.max(0, Math.min(255, normalized));
      data[i] = clamped;
      data[i + 1] = clamped;
      data[i + 2] = clamped;
    }
    ctx.putImageData(imageData, 0, 0);
  }

  if (viewport.invert) {
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imageData.data;
    for (let i = 0; i < data.length; i += 4) {
      data[i] = 255 - data[i];
      data[i + 1] = 255 - data[i + 1];
      data[i + 2] = 255 - data[i + 2];
    }
    ctx.putImageData(imageData, 0, 0);
  }
}

export function OverlayMode({ imageIdA, imageIdB, className }: OverlayModeProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const imgARef = useRef<HTMLImageElement | null>(null);
  const imgBRef = useRef<HTMLImageElement | null>(null);

  const [viewport, setViewport] = useState<ViewportState>({ ...defaultViewport });
  const [opacity, setOpacity] = useState(0.5);
  const [blendMode, setBlendMode] = useState<BlendMode>('normal');
  const [isLoading, setIsLoading] = useState(true);
  const [diffHighlight, setDiffHighlight] = useState(false);

  const loadImage = useCallback(
    (imageId: string, imgRef: React.MutableRefObject<HTMLImageElement | null>) => {
      return new Promise<void>((resolve) => {
        if (!imageId) { resolve(); return; }
        const img = new Image();
        img.crossOrigin = 'anonymous';
        img.onload = () => {
          imgRef.current = img;
          resolve();
        };
        img.onerror = () => {
          imgRef.current = null;
          resolve();
        };
        img.src = `/api/images/${imageId}/file`;
      });
    },
    []
  );

  useEffect(() => {
    setIsLoading(true);
    Promise.all([loadImage(imageIdA, imgARef), loadImage(imageIdB, imgBRef)]).then(() => {
      setIsLoading(false);
    });
  }, [imageIdA, imageIdB, loadImage]);

  useEffect(() => {
    if (canvasRef.current && imgARef.current && imgBRef.current) {
      renderOverlayToCanvas(canvasRef.current, imgARef.current, imgBRef.current, viewport, opacity, blendMode);

      if (diffHighlight) {
        const ctx = canvasRef.current.getContext('2d');
        if (ctx) {
          const imageData = ctx.getImageData(0, 0, canvasRef.current.width, canvasRef.current.height);
          const data = imageData.data;
          for (let i = 0; i < data.length; i += 4) {
            const r = data[i], g = data[i + 1], b = data[i + 2];
            const diff = Math.abs(r - 128) + Math.abs(g - 128) + Math.abs(b - 128);
            if (diff > 60) {
              data[i] = 255;
              data[i + 1] = 50;
              data[i + 2] = 50;
              data[i + 3] = Math.min(255, diff * 3);
            }
          }
          ctx.putImageData(imageData, 0, 0);
        }
      }
    }
  }, [viewport, opacity, blendMode, diffHighlight, isLoading]);

  const handleMouseDown = useCallback(
    (e: React.MouseEvent<HTMLCanvasElement>) => {
      const startX = e.clientX;
      const startY = e.clientY;
      const startPan = { ...viewport.pan };

      const handleMouseMove = (moveEvent: MouseEvent) => {
        const deltaX = moveEvent.clientX - startX;
        const deltaY = moveEvent.clientY - startY;
        setViewport((prev) => ({
          ...prev,
          pan: {
            x: startPan.x + deltaX / prev.zoom,
            y: startPan.y + deltaY / prev.zoom,
          },
        }));
      };

      const handleMouseUp = () => {
        window.removeEventListener('mousemove', handleMouseMove);
        window.removeEventListener('mouseup', handleMouseUp);
      };

      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    },
    [viewport]
  );

  const handleWheel = useCallback(
    (e: React.WheelEvent<HTMLCanvasElement>) => {
      e.preventDefault();
      const zoomFactor = e.deltaY > 0 ? 0.9 : 1.1;
      setViewport((prev) => ({
        ...prev,
        zoom: Math.max(0.1, Math.min(10, prev.zoom * zoomFactor)),
      }));
    },
    []
  );

  return (
    <div className={cn('flex flex-col w-full h-full', className)}>
      <div className="flex items-center gap-4 p-2 bg-card border-b">
        <div className="flex items-center gap-2">
          <label className="text-xs text-muted-foreground">透明度</label>
          <input
            type="range"
            min={0}
            max={1}
            step={0.01}
            value={opacity}
            onChange={(e) => setOpacity(parseFloat(e.target.value))}
            className="w-32"
          />
          <span className="text-xs text-muted-foreground w-10">{(opacity * 100).toFixed(0)}%</span>
        </div>

        <div className="flex items-center gap-2">
          <label className="text-xs text-muted-foreground">混合模式</label>
          <div className="flex gap-1">
            {BLEND_MODES.map((mode) => (
              <Button
                key={mode.value}
                variant={blendMode === mode.value ? 'default' : 'ghost'}
                size="sm"
                onClick={() => setBlendMode(mode.value)}
                className="text-xs h-7"
              >
                {mode.label}
              </Button>
            ))}
          </div>
        </div>

        <Button
          variant={diffHighlight ? 'default' : 'ghost'}
          size="sm"
          onClick={() => setDiffHighlight(!diffHighlight)}
          className="text-xs h-7"
        >
          差异高亮
        </Button>
      </div>

      <div ref={containerRef} className="relative flex-1 bg-black overflow-hidden">
        {isLoading && (
          <div className="absolute inset-0 flex items-center justify-center">
            <div className="text-white text-sm">加载中...</div>
          </div>
        )}
        <canvas
          ref={canvasRef}
          className="w-full h-full cursor-crosshair"
          onMouseDown={handleMouseDown}
          onWheel={handleWheel}
        />
        <div className="absolute bottom-2 left-2 text-xs text-white/70">
          <div>缩放: {(viewport.zoom * 100).toFixed(0)}%</div>
          <div>混合: {BLEND_MODES.find((m) => m.value === blendMode)?.label}</div>
        </div>
      </div>
    </div>
  );
}

import { useEffect, useRef, useState, useCallback } from 'react';
import { cn } from '@/lib/utils';

interface ViewportState {
  zoom: number;
  pan: { x: number; y: number };
  rotation: number;
  flipH: boolean;
  flipV: boolean;
  windowWidth: number;
  windowLevel: number;
  invert: boolean;
}

interface SliderModeProps {
  imageIdA: string;
  imageIdB: string;
  orientation?: 'horizontal' | 'vertical';
  className?: string;
}

const defaultViewport: ViewportState = {
  zoom: 1,
  pan: { x: 0, y: 0 },
  rotation: 0,
  flipH: false,
  flipV: false,
  windowWidth: 400,
  windowLevel: 40,
  invert: false,
};

function renderImageToCanvas(
  canvas: HTMLCanvasElement,
  img: HTMLImageElement,
  viewport: ViewportState
) {
  const ctx = canvas.getContext('2d');
  if (!ctx) return;

  ctx.clearRect(0, 0, canvas.width, canvas.height);
  ctx.save();

  ctx.translate(canvas.width / 2, canvas.height / 2);
  ctx.scale(viewport.zoom, viewport.zoom);
  ctx.rotate((viewport.rotation * Math.PI) / 180);
  if (viewport.flipH) ctx.scale(-1, 1);
  if (viewport.flipV) ctx.scale(1, -1);
  ctx.translate(viewport.pan.x, viewport.pan.y);

  const scale = Math.min(canvas.width / img.width, canvas.height / img.height) * 0.9;
  const x = (-img.width * scale) / 2;
  const y = (-img.height * scale) / 2;

  ctx.drawImage(img, x, y, img.width * scale, img.height * scale);

  if (viewport.windowWidth !== 400 || viewport.windowLevel !== 40) {
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imageData.data;
    const min = viewport.windowLevel - viewport.windowWidth / 2;
    const max = viewport.windowLevel + viewport.windowWidth / 2;

    for (let i = 0; i < data.length; i += 4) {
      const gray = (data[i] + data[i + 1] + data[i + 2]) / 3;
      const normalized = ((gray - min) / (max - min)) * 255;
      const clamped = Math.max(0, Math.min(255, normalized));
      data[i] = clamped;
      data[i + 1] = clamped;
      data[i + 2] = clamped;
    }
    ctx.putImageData(imageData, 0, 0);
  }

  if (viewport.invert) {
    const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
    const data = imageData.data;
    for (let i = 0; i < data.length; i += 4) {
      data[i] = 255 - data[i];
      data[i + 1] = 255 - data[i + 1];
      data[i + 2] = 255 - data[i + 2];
    }
    ctx.putImageData(imageData, 0, 0);
  }

  ctx.restore();
}

export function SliderMode({
  imageIdA,
  imageIdB,
  orientation = 'horizontal',
  className,
}: SliderModeProps) {
  const canvasRef = useRef<HTMLCanvasElement>(null);
  const containerRef = useRef<HTMLDivElement>(null);
  const imgARef = useRef<HTMLImageElement | null>(null);
  const imgBRef = useRef<HTMLImageElement | null>(null);

  const [viewport, setViewport] = useState<ViewportState>({ ...defaultViewport });
  const [sliderPosition, setSliderPosition] = useState(0.5);
  const [isDragging, setIsDragging] = useState(false);
  const [isLoading, setIsLoading] = useState(true);

  const loadImage = useCallback(
    (imageId: string, imgRef: React.MutableRefObject<HTMLImageElement | null>) => {
      return new Promise<void>((resolve) => {
        if (!imageId) { resolve(); return; }
        const img = new Image();
        img.crossOrigin = 'anonymous';
        img.onload = () => {
          imgRef.current = img;
          resolve();
        };
        img.onerror = () => {
          imgRef.current = null;
          resolve();
        };
        img.src = `/api/images/${imageId}/file`;
      });
    },
    []
  );

  useEffect(() => {
    setIsLoading(true);
    Promise.all([loadImage(imageIdA, imgARef), loadImage(imageIdB, imgBRef)]).then(() => {
      setIsLoading(false);
    });
  }, [imageIdA, imageIdB, loadImage]);

  useEffect(() => {
    if (!canvasRef.current || !imgARef.current || !imgBRef.current) return;

    const canvas = canvasRef.current;
    const ctx = canvas.getContext('2d');
    if (!ctx) return;

    const container = containerRef.current;
    if (container) {
      canvas.width = container.clientWidth;
      canvas.height = container.clientHeight;
    }

    ctx.clearRect(0, 0, canvas.width, canvas.height);

    const isHorizontal = orientation === 'horizontal';
    const splitPoint = isHorizontal
      ? Math.floor(canvas.width * sliderPosition)
      : Math.floor(canvas.height * sliderPosition);

    // Draw image A on one side
    ctx.save();
    if (isHorizontal) {
      ctx.beginPath();
      ctx.rect(0, 0, splitPoint, canvas.height);
    } else {
      ctx.beginPath();
      ctx.rect(0, 0, canvas.width, splitPoint);
    }
    ctx.clip();

    // Inline render for A
    ctx.translate(canvas.width / 2, canvas.height / 2);
    ctx.scale(viewport.zoom, viewport.zoom);
    ctx.rotate((viewport.rotation * Math.PI) / 180);
    if (viewport.flipH) ctx.scale(-1, 1);
    if (viewport.flipV) ctx.scale(1, -1);
    ctx.translate(viewport.pan.x, viewport.pan.y);

    const imgA = imgARef.current;
    const scaleA = Math.min(canvas.width / imgA.width, canvas.height / imgA.height) * 0.9;
    ctx.drawImage(
      imgA,
      (-imgA.width * scaleA) / 2,
      (-imgA.height * scaleA) / 2,
      imgA.width * scaleA,
      imgA.height * scaleA
    );
    ctx.restore();

    // Draw image B on other side
    ctx.save();
    if (isHorizontal) {
      ctx.beginPath();
      ctx.rect(splitPoint, 0, canvas.width - splitPoint, canvas.height);
    } else {
      ctx.beginPath();
      ctx.rect(0, splitPoint, canvas.width, canvas.height - splitPoint);
    }
    ctx.clip();

    ctx.translate(canvas.width / 2, canvas.height / 2);
    ctx.scale(viewport.zoom, viewport.zoom);
    ctx.rotate((viewport.rotation * Math.PI) / 180);
    if (viewport.flipH) ctx.scale(-1, 1);
    if (viewport.flipV) ctx.scale(1, -1);
    ctx.translate(viewport.pan.x, viewport.pan.y);

    const imgB = imgBRef.current;
    const scaleB = Math.min(canvas.width / imgB.width, canvas.height / imgB.height) * 0.9;
    ctx.drawImage(
      imgB,
      (-imgB.width * scaleB) / 2,
      (-imgB.height * scaleB) / 2,
      imgB.width * scaleB,
      imgB.height * scaleB
    );
    ctx.restore();

    // Draw slider line
    ctx.save();
    ctx.strokeStyle = '#3b82f6';
    ctx.lineWidth = 2;
    ctx.setLineDash([6, 4]);

    if (isHorizontal) {
      ctx.beginPath();
      ctx.moveTo(splitPoint, 0);
      ctx.lineTo(splitPoint, canvas.height);
      ctx.stroke();

      // Slider handle
      ctx.fillStyle = '#3b82f6';
      ctx.beginPath();
      ctx.arc(splitPoint, canvas.height / 2, 16, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = '#fff';
      ctx.font = '12px sans-serif';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText('⇔', splitPoint, canvas.height / 2);
    } else {
      ctx.beginPath();
      ctx.moveTo(0, splitPoint);
      ctx.lineTo(canvas.width, splitPoint);
      ctx.stroke();

      ctx.fillStyle = '#3b82f6';
      ctx.beginPath();
      ctx.arc(canvas.width / 2, splitPoint, 16, 0, Math.PI * 2);
      ctx.fill();
      ctx.fillStyle = '#fff';
      ctx.font = '12px sans-serif';
      ctx.textAlign = 'center';
      ctx.textBaseline = 'middle';
      ctx.fillText('⇕', canvas.width / 2, splitPoint);
    }

    ctx.setLineDash([]);
    ctx.restore();

    // Apply window/level
    if (viewport.windowWidth !== 400 || viewport.windowLevel !== 40) {
      const imageData = ctx.getImageData(0, 0, canvas.width, canvas.height);
      const data = imageData.data;
      const min = viewport.windowLevel - viewport.windowWidth / 2;
      const max = viewport.windowLevel + viewport.windowWidth / 2;

      for (let i = 0; i < data.length; i += 4) {
        const gray = (data[i] + data[i + 1] + data[i + 2]) / 3;
        const normalized = ((gray - min) / (max - min)) * 255;
        const clamped = Math.max(0, Math.min(255, normalized));
        data[i] = clamped;
        data[i + 1] = clamped;
        data[i + 2] = clamped;
      }
      ctx.putImageData(imageData, 0, 0);
    }
  }, [viewport, sliderPosition, orientation, isLoading]);

  const updateSliderFromEvent = useCallback(
    (clientX: number, clientY: number) => {
      const container = containerRef.current;
      if (!container) return;
      const rect = container.getBoundingClientRect();

      if (orientation === 'horizontal') {
        const x = clientX - rect.left;
        setSliderPosition(Math.max(0, Math.min(1, x / rect.width)));
      } else {
        const y = clientY - rect.top;
        setSliderPosition(Math.max(0, Math.min(1, y / rect.height)));
      }
    },
    [orientation]
  );

  const handleMouseDown = useCallback(
    (e: React.MouseEvent<HTMLCanvasElement>) => {
      setIsDragging(true);
      updateSliderFromEvent(e.clientX, e.clientY);

      const handleMouseMove = (moveEvent: MouseEvent) => {
        updateSliderFromEvent(moveEvent.clientX, moveEvent.clientY);
      };

      const handleMouseUp = () => {
        setIsDragging(false);
        window.removeEventListener('mousemove', handleMouseMove);
        window.removeEventListener('mouseup', handleMouseUp);
      };

      window.addEventListener('mousemove', handleMouseMove);
      window.addEventListener('mouseup', handleMouseUp);
    },
    [updateSliderFromEvent]
  );

  const handleWheel = useCallback(
    (e: React.WheelEvent<HTMLCanvasElement>) => {
      e.preventDefault();
      const zoomFactor = e.deltaY > 0 ? 0.9 : 1.1;
      setViewport((prev) => ({
        ...prev,
        zoom: Math.max(0.1, Math.min(10, prev.zoom * zoomFactor)),
      }));
    },
    []
  );

  return (
    <div ref={containerRef} className={cn('relative w-full h-full bg-black overflow-hidden', className)}>
      {isLoading && (
        <div className="absolute inset-0 flex items-center justify-center">
          <div className="text-white text-sm">加载中...</div>
        </div>
      )}
      <canvas
        ref={canvasRef}
        className="w-full h-full cursor-ew-resize"
        onMouseDown={handleMouseDown}
        onWheel={handleWheel}
      />
      <div className="absolute top-2 left-2 text-xs text-white/70 bg-black/50 px-2 py-1 rounded">
        A
      </div>
      <div className="absolute top-2 right-2 text-xs text-white/70 bg-black/50 px-2 py-1 rounded">
        B
      </div>
      <div className="absolute bottom-2 left-2 text-xs text-white/70">
        <div>缩放: {(viewport.zoom * 100).toFixed(0)}%</div>
        <div>滑块位置: {(sliderPosition * 100).toFixed(0)}%</div>
      </div>
    </div>
  );
}

import { useState } from 'react';
import { cn } from '@/lib/utils';
import { Button } from '@/components/ui/button';
import { SideBySideMode } from './SideBySideMode';
import { OverlayMode } from './OverlayMode';
import { SliderMode } from './SliderMode';
import {
  Columns,
  Layers,
  SlidersHorizontal,
} from 'lucide-react';

export type ComparisonMode = 'side-by-side' | 'overlay' | 'slider';

interface ComparisonViewProps {
  imageIdA: string;
  imageIdB: string;
  initialMode?: ComparisonMode;
  className?: string;
}

const MODE_OPTIONS: { value: ComparisonMode; label: string; icon: typeof Columns }[] = [
  { value: 'side-by-side', label: '并排对比', icon: Columns },
  { value: 'overlay', label: '叠加对比', icon: Layers },
  { value: 'slider', label: '滑动对比', icon: SlidersHorizontal },
];

export function ComparisonView({
  imageIdA,
  imageIdB,
  initialMode = 'side-by-side',
  className,
}: ComparisonViewProps) {
  const [mode, setMode] = useState<ComparisonMode>(initialMode);
  const [sideOrientation, setSideOrientation] = useState<'horizontal' | 'vertical'>('horizontal');
  const [sliderOrientation, setSliderOrientation] = useState<'horizontal' | 'vertical'>('horizontal');

  if (!imageIdA || !imageIdB) {
    return (
      <div className={cn('flex items-center justify-center bg-black text-white', className)}>
        <div className="text-center">
          <p className="text-lg font-medium">请选择两张图像进行对比</p>
          <p className="text-sm text-muted-foreground mt-1">从图像列表中选择图像 A 和图像 B</p>
        </div>
      </div>
    );
  }

  return (
    <div className={cn('flex flex-col w-full h-full', className)}>
      {/* Mode selector */}
      <div className="flex items-center gap-2 p-2 bg-card border-b">
        <div className="flex gap-1">
          {MODE_OPTIONS.map((option) => {
            const Icon = option.icon;
            return (
              <Button
                key={option.value}
                variant={mode === option.value ? 'default' : 'ghost'}
                size="sm"
                onClick={() => setMode(option.value)}
                className="text-xs h-8"
              >
                <Icon className="h-4 w-4 mr-1" />
                {option.label}
              </Button>
            );
          })}
        </div>

        {mode === 'side-by-side' && (
          <div className="flex gap-1 ml-2">
            <Button
              variant={sideOrientation === 'horizontal' ? 'secondary' : 'ghost'}
              size="sm"
              onClick={() => setSideOrientation('horizontal')}
              className="text-xs h-7"
            >
              左右
            </Button>
            <Button
              variant={sideOrientation === 'vertical' ? 'secondary' : 'ghost'}
              size="sm"
              onClick={() => setSideOrientation('vertical')}
              className="text-xs h-7"
            >
              上下
            </Button>
          </div>
        )}

        {mode === 'slider' && (
          <div className="flex gap-1 ml-2">
            <Button
              variant={sliderOrientation === 'horizontal' ? 'secondary' : 'ghost'}
              size="sm"
              onClick={() => setSliderOrientation('horizontal')}
              className="text-xs h-7"
            >
              水平
            </Button>
            <Button
              variant={sliderOrientation === 'vertical' ? 'secondary' : 'ghost'}
              size="sm"
              onClick={() => setSliderOrientation('vertical')}
              className="text-xs h-7"
            >
              垂直
            </Button>
          </div>
        )}
      </div>

      {/* Comparison content */}
      <div className="flex-1 overflow-hidden">
        {mode === 'side-by-side' && (
          <SideBySideMode
            imageIdA={imageIdA}
            imageIdB={imageIdB}
            orientation={sideOrientation}
          />
        )}
        {mode === 'overlay' && (
          <OverlayMode imageIdA={imageIdA} imageIdB={imageIdB} />
        )}
        {mode === 'slider' && (
          <SliderMode
            imageIdA={imageIdA}
            imageIdB={imageIdB}
            orientation={sliderOrientation}
          />
        )}
      </div>
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useSearchParams, Link } from 'react-router-dom';
import { useTranslation } from 'react-i18next';
import { studyApi, imageApi } from '@/services/api';
import { Button } from '@/components/ui/button';
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card';
import { ComparisonView } from '@/components/comparison/ComparisonView';
import { ArrowLeft, Image as ImageIcon } from 'lucide-react';
import { cn } from '@/lib/utils';

interface Image {
  id: string;
  filePath: string;
  thumbnailPath?: string;
  width: number;
  height: number;
  format: string;
  instanceNumber: number;
}

interface Study {
  id: string;
  patientId: string;
  studyDate: string;
  studyType: string;
  modality: string;
  patient?: {
    name: string;
    mrn: string;
  };
}

export function ComparisonPage() {
  const [searchParams] = useSearchParams();
  const studyId = searchParams.get('studyId');
  const { t } = useTranslation();

  const [study, setStudy] = useState<Study | null>(null);
  const [images, setImages] = useState<Image[]>([]);
  const [selectedImageA, setSelectedImageA] = useState<string | null>(null);
  const [selectedImageB, setSelectedImageB] = useState<string | null>(null);
  const [selectionMode, setSelectionMode] = useState<'A' | 'B'>('A');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    if (studyId) {
      loadStudy(studyId);
      loadImages(studyId);
    } else {
      setLoading(false);
    }
  }, [studyId]);

  const loadStudy = async (id: string) => {
    try {
      const response = await studyApi.getById(id);
      setStudy(response.data);
    } catch (error) {
      console.error('Failed to load study:', error);
    }
  };

  const loadImages = async (id: string) => {
    try {
      const seriesResponse = await studyApi.getSeries(id);
      const series = seriesResponse.data || [];
      if (series.length > 0) {
        const imagesResponse = await imageApi.search({ seriesId: series[0].id });
        const imageList = imagesResponse.data || [];
        setImages(imageList);
        if (imageList.length >= 2) {
          setSelectedImageA(imageList[0].id);
          setSelectedImageB(imageList[1].id);
        } else if (imageList.length === 1) {
          setSelectedImageA(imageList[0].id);
        }
      }
    } catch (error) {
      console.error('Failed to load images:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleImageSelect = (imageId: string) => {
    if (selectionMode === 'A') {
      setSelectedImageA(imageId);
      setSelectionMode('B');
    } else {
      setSelectedImageB(imageId);
      setSelectionMode('A');
    }
  };

  if (loading) {
    return <div className="text-center py-8">加载中...</div>;
  }

  return (
    <div className="flex h-[calc(100vh-8rem)] space-x-4">
      {/* Main comparison view */}
      <div className="flex-1 flex flex-col">
        {/* Header */}
        <div className="flex items-center justify-between mb-4">
          <div className="flex items-center space-x-4">
            <Button variant="ghost" size="icon" asChild>
              <Link to={studyId ? `/patients/${study?.patientId}` : '/'}>
                <ArrowLeft className="h-4 w-4" />
              </Link>
            </Button>
            <div>
              <h1 className="text-2xl font-bold">图像对比</h1>
              {study && (
                <p className="text-sm text-muted-foreground">
                  {study.patient?.name} - {study.studyType.toUpperCase()} - {study.studyDate}
                </p>
              )}
            </div>
          </div>
        </div>

        {/* Comparison View */}
        <Card className="flex-1 overflow-hidden">
          <CardContent className="p-0 h-full">
            <ComparisonView
              imageIdA={selectedImageA || ''}
              imageIdB={selectedImageB || ''}
            />
          </CardContent>
        </Card>
      </div>

      {/* Sidebar - Image selection */}
      <div className="w-80 flex flex-col space-y-4">
        {/* Selection info */}
        <Card>
          <CardHeader className="pb-2">
            <CardTitle className="text-sm">选择对比图像</CardTitle>
          </CardHeader>
          <CardContent>
            <div className="space-y-3">
              <div className="flex items-center justify-between">
                <span className="text-sm text-muted-foreground">当前选择:</span>
                <div className="flex gap-1">
                  <Button
                    variant={selectionMode === 'A' ? 'default' : 'ghost'}
                    size="sm"
                    onClick={() => setSelectionMode('A')}
                    className="h-7 text-xs"
                  >
                    图像 A
                  </Button>
                  <Button
                    variant={selectionMode === 'B' ? 'default' : 'ghost'}
                    size="sm"
                    onClick={() => setSelectionMode('B')}
                    className="h-7 text-xs"
                  >
                    图像 B
                  </Button>
                </div>
              </div>

              <div className="grid grid-cols-2 gap-2 text-xs">
                <div className="bg-muted rounded p-2">
                  <span className="text-muted-foreground">A:</span>{' '}
                  {selectedImageA
                    ? `#${images.find((i) => i.id === selectedImageA)?.instanceNumber || '?'}`
                    : '未选择'}
                </div>
                <div className="bg-muted rounded p-2">
                  <span className="text-muted-foreground">B:</span>{' '}
                  {selectedImageB
                    ? `#${images.find((i) => i.id === selectedImageB)?.instanceNumber || '?'}`
                    : '未选择'}
                </div>
              </div>
            </div>
          </CardContent>
        </Card>

        {/* Image list */}
        <Card className="flex-1 overflow-hidden">
          <CardHeader className="pb-2">
            <CardTitle className="text-sm">图像列表</CardTitle>
          </CardHeader>
          <CardContent className="p-0 overflow-y-auto max-h-[500px]">
            <div className="grid grid-cols-3 gap-1 p-2">
              {images.map((image) => {
                const isA = selectedImageA === image.id;
                const isB = selectedImageB === image.id;
                const isSelected = isA || isB;

                return (
                  <button
                    key={image.id}
                    className={cn(
                      'relative aspect-square overflow-hidden rounded border-2 transition-colors',
                      isSelected
                        ? isA
                          ? 'border-blue-500'
                          : 'border-green-500'
                        : 'border-transparent hover:border-primary/50'
                    )}
                    onClick={() => handleImageSelect(image.id)}
                  >
                    {image.thumbnailPath ? (
                      <img
                        src={image.thumbnailPath}
                        alt={`Image ${image.instanceNumber}`}
                        className="h-full w-full object-cover"
                      />
                    ) : (
                      <div className="flex h-full w-full items-center justify-center bg-muted text-xs text-muted-foreground">
                        <ImageIcon className="h-4 w-4 mr-1" />
                        {image.instanceNumber}
                      </div>
                    )}
                    {isSelected && (
                      <div
                        className={cn(
                          'absolute top-0.5 right-0.5 text-white text-xs px-1 rounded',
                          isA ? 'bg-blue-500' : 'bg-green-500'
                        )}
                      >
                        {isA ? 'A' : 'B'}
                      </div>
                    )}
                  </button>
                );
              })}
            </div>
            {images.length === 0 && (
              <div className="text-center py-8 text-muted-foreground text-sm">
                暂无图像
              </div>
            )}
          </CardContent>
        </Card>
      </div>
    </div>
  );
}

